<template>
  <div class="m-emoji" @click="close">
    <div class="u-wrap">
      <swiper :indicator-dots="false" :autoplay="false" :current="sIndex" duration="300" @animationfinish="handleChange">
        <swiper-item>
          <div class="u-img-box" v-for="(item,index) in arr1" :key="index" @click.stop="throttle(index,400)">
            <img :src="item.imgUrl">
          </div>
        </swiper-item>
         <swiper-item>
           <div class="u-img-box" v-for="(item,index) in arr2" :key="index"@click.stop="throttle(index+6,400)">
            <img :src="item.imgUrl">
           </div>
        </swiper-item>
      </swiper>
      <div class="u-dot">
        <div :class="{'active':sIndex==0}"></div>
        <div :class="{'active':sIndex==1}"></div>
      </div>
    </div>
    
  </div>
</template>

<script>

import {emoji} from "@/config/dataFile"
export default {
  data(){
    return{
      sIndex:0,
      sendTimer:null,
      throttleTimer:null,
      sendTime:0,
      arr1:[],
      arr2:[],
    }
  },
  watch:{
    sendTime(val){
      if(val>=5){
        clearInterval(this.sendTimer);
        this.sendTime=0;
      }
    },
  },
  computed:{
    appInfo(){
      return this.store.state.appInfo;
    }
  },
  methods:{
    handleChange(event){
        this.sIndex = event.mp.detail.current;
    },
    close(){
      this.$emit("close");
    },
    throttle(index,delay) {
      clearTimeout(this.throttleTimer);
      this.throttleTimer = setTimeout(()=> {
        this.sendEmoji(index);
      }, delay);
    },
    sendEmoji(index){
      if(this.sendTime==0){
        this.sendTimer=setInterval(()=>{
          this.sendTime++;
        },1000)
        let emojiInfo=`{index:${index},userId:${this.appInfo.userId},userName:'${this.appInfo.nickname}'}`;
        this.close();
        this.$emit("sendEmoji",emojiInfo);
      }else{
        wx.showToast({title:"5s内只能发一次",icon:"none"});
      }
    },
  },
  mounted(){
    this.arr1 = emoji.slice(0,6);
    this.arr2 = emoji.slice(6);
  },
}
</script>

<style lang="scss" scoped>
.m-emoji{
  position: fixed;
  left: 0;
  top: 0;
  width: 100%;
  height: 100%;
  background: rgba(#000,.55);
  display: flex;
  justify-content: center;
  z-index: 10;
}
.u-wrap{
  margin-top: 60rpx;
  width: 600rpx;
  height: 945rpx;
  background-size:100%;
  background-image: url("data:image/png;base64,");
  padding: 50rpx 10rpx 105rpx 10rpx;
  box-sizing: border-box;
}
swiper{
  width: 100%;
  height: 720rpx;
}
swiper-item{
  width: 100%;
  height: 100%;
  display: flex;
  justify-content: center;
  flex-wrap: wrap;
  .u-img-box,img{
    width: 264rpx;
    height: 210rpx;
  }

}
.u-dot{
  width: 100%;
  height: 100rpx;
  display: flex;
  justify-content: center;
  align-items: center;
  div{
    width: 22rpx;
    height: 22rpx;
    background: #29234f;
    border-radius: 50%;
    margin-right: 12rpx;
    &:last-child{
      margin-right: 0;
    }
  }
  .active{
    background: #ff217b;
  }
}


</style>



